SELECT AVG(avg_water_quality) AS average_water_quality
FROM annual_data
WHERE year = 2010;

SELECT AVG(discharge_mean_cfs) AS average_discharge
FROM discharge_data
WHERE station_id = 1 AND year = 2010;

SELECT station_id, year, AVG(discharge_mean_cfs) AS avg_discharge, MAX(max_discharge_cfs) AS peak_discharge, COUNT(discharge_id) AS record_count
FROM discharge_data
GROUP BY station_id, year;

SELECT AVG(discharge_mean_cfs) AS avg_discharge, TANH(ann_et) AS tanh_ann_et
FROM hydrological_data
WHERE year = 2010;
